SELECT t_score 
FROM t_scores 
WHERE student_id = 1;

SELECT score 
FROM assessments_taken 
WHERE score > 80 AND attempt_number > 1;

SELECT student_name 
FROM students 
WHERE student_id = (
    SELECT student_id 
    FROM assessments_taken 
    WHERE score = (
        SELECT MAX(score) 
        FROM assessments_taken
    )
);

SELECT MAX(score) 
FROM assessments_taken 
WHERE assessment_id = 1 AND student_id = 1;

SELECT AVG(score) AS average_score 
FROM student_scores 
WHERE assessment_id = 1;

SELECT COUNT(DISTINCT assessment_id) AS total_assessments
FROM assessments_taken
WHERE student_id = 1;
